import{_ as o,C as n,o as t,c as r,a0 as a,b as l,w as s,a as c,E as d,a1 as p}from"./chunks/framework.DZNqfkJl.js";const C=JSON.parse('{"title":"Backend Setup and Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/backend.md","filePath":"en/backend.md"}'),h={name:"en/backend.md"};function u(g,e,m,b,k,f){const i=n("Mermaid");return t(),r("div",null,[e[1]||(e[1]=a('<h1 id="backend-setup-and-architecture" tabindex="-1">Backend Setup and Architecture <a class="header-anchor" href="#backend-setup-and-architecture" aria-label="Permalink to &quot;Backend Setup and Architecture&quot;">​</a></h1><p>The <strong>Structo</strong> backend is built on <strong>.NET 10</strong> using C#. It follows <strong>Clean Architecture</strong> and <strong>N-Tier</strong> principles to ensure the codebase remains maintainable, testable, and loosely coupled from external technologies.</p><h2 id="🚀-how-to-run-locally" tabindex="-1">🚀 How to Run Locally <a class="header-anchor" href="#🚀-how-to-run-locally" aria-label="Permalink to &quot;🚀 How to Run Locally&quot;">​</a></h2><h3 id="_1-database-preparation" tabindex="-1">1. Database Preparation <a class="header-anchor" href="#_1-database-preparation" aria-label="Permalink to &quot;1. Database Preparation&quot;">​</a></h3><p>Ensure your databases (SQL Server and MongoDB) are running. You can bring up the containers using a <code>docker-compose.yml</code> file (if available in the root or <code>docker/</code> folder):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>Alternatively, use your local instances. Make sure to configure the correct connection strings in the <code>appsettings.Development.json</code> files within the main WebApi project.</p><h3 id="_2-run-migrations-entity-framework" tabindex="-1">2. Run Migrations (Entity Framework) <a class="header-anchor" href="#_2-run-migrations-entity-framework" aria-label="Permalink to &quot;2. Run Migrations (Entity Framework)&quot;">​</a></h3><p>Enter the backend project. You can apply migrations to the SQL Server database in two ways:</p><ul><li><strong>Option 1: Using automated scripts (Recommended)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./ef.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div></li><li><strong>Option 2: Using standard <code>dotnet</code> CLI</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> database</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.Infrastructure/Structo.Infrastructure.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><h3 id="_3-loading-initial-data-seed" tabindex="-1">3. Loading Initial Data (Seed) <a class="header-anchor" href="#_3-loading-initial-data-seed" aria-label="Permalink to &quot;3. Loading Initial Data (Seed)&quot;">​</a></h3><p>The backend project is configured to run the <em>Seeding</em> process <strong>automatically</strong> every time the application starts. During startup (<code>Program.cs</code>), if foundational entities are missing, the system will auto-insert them using <code>InitDatabase</code>.</p><h3 id="_4-run-the-project" tabindex="-1">4. Run the Project <a class="header-anchor" href="#_4-run-the-project" aria-label="Permalink to &quot;4. Run the Project&quot;">​</a></h3><p>Similar to migrations, you have two alternatives for running the Web API:</p><ul><li><strong>Option 1: Using automated scripts (Recommended)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./dev.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div></li><li><strong>Option 2: Using standard <code>dotnet</code> CLI</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><p>The development server will initiate and you should be able to access the interactive API interface (Swagger) by navigating to:</p><ul><li><code>http://localhost:5000/swagger</code> or</li><li><code>https://localhost:5001/swagger</code> (if you used the <code>dev.sh run</code> command with the active HTTPS profile).</li></ul><hr><h2 id="🛠️-helper-commands-list-automated-scripts" tabindex="-1">🛠️ Helper Commands List (Automated Scripts) <a class="header-anchor" href="#🛠️-helper-commands-list-automated-scripts" aria-label="Permalink to &quot;🛠️ Helper Commands List (Automated Scripts)&quot;">​</a></h2><p>To streamline the workflow, the repository provides two <code>.sh</code> scripts at the root of the backend directory:</p><h3 id="script-dev-sh" tabindex="-1">Script <code>dev.sh</code> <a class="header-anchor" href="#script-dev-sh" aria-label="Permalink to &quot;Script `dev.sh`&quot;">​</a></h3><p>Wraps the .NET CLI by appending the default configurations and the HTTPS launch profile.</p><ul><li><code>./dev.sh run</code>: Runs the application with the HTTPS profile.</li><li><code>./dev.sh watch</code>: Runs the application with Hot Reload (watch) enabled.</li><li><code>./dev.sh build</code>: Builds the entire solution.</li><li><code>./dev.sh build-errors</code>: Builds the solution but outputs only compilation errors.</li><li><code>./dev.sh test</code>: Runs all automatic tests found (Unit and Integration).</li><li><code>./dev.sh clean</code>: Cleans the compiled solution.</li><li><code>./dev.sh restore</code>: Restores all NuGet packages.</li></ul><h3 id="script-ef-sh" tabindex="-1">Script <code>ef.sh</code> <a class="header-anchor" href="#script-ef-sh" aria-label="Permalink to &quot;Script `ef.sh`&quot;">​</a></h3><p>Wraps <code>dotnet ef</code> by pre-setting the correct paths to the Infrastructure and WebApi projects.</p><ul><li><code>./ef.sh add &lt;name&gt;</code>: Adds a new migration.</li><li><code>./ef.sh update</code>: Applies pending migrations to the database.</li><li><code>./ef.sh remove</code>: Reverts and deletes the last migration.</li><li><code>./ef.sh list</code>: Lists all existing migrations.</li></ul><hr><h2 id="🏗️-applied-design-patterns" tabindex="-1">🏗️ Applied Design Patterns <a class="header-anchor" href="#🏗️-applied-design-patterns" aria-label="Permalink to &quot;🏗️ Applied Design Patterns&quot;">​</a></h2><p>During the backend development, the following architectural patterns are actively promoted:</p><ul><li><strong>Dependency Injection (DI)</strong>: Natively used within .NET Core to inject services into controllers and other layers, promoting low coupling.</li><li><strong>Repository Pattern</strong>: Data access abstraction provided by interfaces inside the <code>Domain</code> and physically implemented in the <code>Infrastructure</code> layer.</li><li><strong>Data Transfer Objects (DTO)</strong>: Completely isolating the controller responses from mapping directly to domain models.</li><li><strong>CQRS (Optional, based on complexity)</strong>: Lightweight separation between reads and mutations handled gracefully in the services layer.</li></ul><h2 id="📁-project-structure-n-tier" tabindex="-1">📁 Project Structure (N-Tier) <a class="header-anchor" href="#📁-project-structure-n-tier" aria-label="Permalink to &quot;📁 Project Structure (N-Tier)&quot;">​</a></h2><p>The solution (<code>Structo.sln</code>) and the <code>src/</code> directory are conceptually split into class libraries:</p>',32)),(t(),l(p,null,{default:s(()=>[d(i,{id:"mermaid-193",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20API%5BStructo.WebApi%5CnPresentation%20Layer%5D%20--%3E%20S%5BStructo.Services%5CnApplication%20Logic%5D%0A%20%20%20%20API%20--%3E%20DTO%5BStructo.DTO%5CnData%20Contracts%5D%0A%20%20%20%20S%20--%3E%20DOM%5BStructo.Domain%5CnBusiness%20Rules%20%2F%20Entities%5D%0A%20%20%20%20S%20--%3E%20INF%5BStructo.Infrastructure%5CnData%20Access%20%2F%20EF%20Core%5D%0A%20%20%20%20INF%20--%3E%20DOM%0A%20%20%20%20API%20-.%20Injects%20.-%3E%20INF%0A%20%20%20%20%0A%20%20%20%20style%20API%20fill%3A%232a70d9%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20S%20fill%3A%230b8a4f%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20INF%20fill%3A%23d9702a%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h3 id="layer-descriptions" tabindex="-1">Layer Descriptions <a class="header-anchor" href="#layer-descriptions" aria-label="Permalink to &quot;Layer Descriptions&quot;">​</a></h3><ol><li><strong>Structo.WebApi</strong>: Contains Controllers (HTTP Endpoints), host configuration, and the dependency injection registry (<code>Program.cs</code>). Responsible for handling requests and returning DTOs.</li><li><strong>Structo.Services</strong>: Contains application logic. Coordinates interactions with the database via interfaces, and applies business orchestration mapping Domain Entities to/from DTOs.</li><li><strong>Structo.Domain</strong>: The core of the system. Contains Entities (table models), Enums, core Interfaces, and pure business logic strictness. <strong>It has zero references to any other project in the solution</strong>.</li><li><strong>Structo.Infrastructure</strong>: Contains <code>DbContext</code> classes (Entity Framework), concrete repository implementations, and setups for external databases (SQL Server / MongoDB). Depends on <code>Structo.Domain</code>.</li><li><strong>Structo.DTO</strong>: Contains flat structures that transport the requested data to the boundaries of the API, avoiding directly exposing Domain classes.</li><li><strong>Structo.Common</strong>: Cross-cutting constants, shared custom exceptions, and extension methods utilized across the whole platform.</li></ol>',2))])}const v=o(h,[["render",u]]);export{C as __pageData,v as default};
